package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotSame;
import static org.junit.jupiter.api.Assertions.assertSame;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.TimeoutException;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.OptimizationGoal;
import org.junit.jupiter.api.Test;

class PackedPlanCacheTest {

	@Test
	void validatedPlanHitBypassesEncodingAndSearch() {
		PackedPlanCache cache = new PackedPlanCache(32, 4);
		PackedPlanCache.Context context = context(11L);
		TupleExpr source = connectedJoin("left", "right");

		PackedPlanningResult cold = PackedCascadesPlanner.optimize(source, OptimizationGoal.root(), cache, context);
		PackedPlanningResult hot = PackedCascadesPlanner.optimize(source, OptimizationGoal.root(), cache, context);

		assertFalse(cold.metrics().planCacheHit());
		assertTrue(hot.metrics().planCacheHit());
		assertEquals(0L, hot.metrics().encodeNanos());
		assertEquals(0L, hot.metrics().searchNanos());
		assertEquals(cold.selectedPlan(), hot.selectedPlan());
		assertNotSame(cold.selectedPlan(), hot.selectedPlan());
	}

	@Test
	void planConfigurationMissReusesImmutableQueryTemplate() {
		PackedPlanCache cache = new PackedPlanCache(32, 4);
		TupleExpr source = connectedJoin("left", "right");
		PackedCascadesPlanner.optimize(source, OptimizationGoal.root(), cache, context(11L));

		PackedPlanningResult revised = PackedCascadesPlanner.optimize(source, OptimizationGoal.root(), cache,
				new PackedPlanCache.Context(1L, 2L, 3L, 4L, 5L, 7L, 11L));

		assertFalse(revised.metrics().planCacheHit());
		assertTrue(revised.metrics().queryTemplateCacheHit());
		assertEquals(0L, revised.metrics().encodeNanos());
	}

	@Test
	void fingerprintCollisionNeverReusesAnUnequalQuery() {
		PackedPlanCache cache = new PackedPlanCache(32, 4, ignored -> new PackedPlanCache.Fingerprint(7L, 9L));
		PackedPlanCache.Context context = context(11L);
		TupleExpr first = connectedJoin("left", "right");
		TupleExpr second = connectedJoin("differentLeft", "differentRight");
		PackedCascadesPlanner.optimize(first, OptimizationGoal.root(), cache, context);

		PackedPlanningResult collision = PackedCascadesPlanner.optimize(second, OptimizationGoal.root(), cache,
				context);

		assertFalse(collision.metrics().planCacheHit());
		assertFalse(collision.metrics().queryTemplateCacheHit());
		assertEquals(second, collision.selectedPlan());
	}

	@Test
	void saturatedFlightTableNeverCreatesAnUntrackedSecondOwner() throws Exception {
		PackedPlanCache cache = new PackedPlanCache(1, 1,
				ignored -> new PackedPlanCache.Fingerprint(7L, 9L));
		PackedPlanCache.Context context = context(11L);
		TupleExpr first = connectedJoin("firstLeft", "firstRight");
		TupleExpr second = connectedJoin("secondLeft", "secondRight");
		TupleExpr third = connectedJoin("thirdLeft", "thirdRight");
		PackedPlanCache.Fingerprint fingerprint = cache.fingerprint(first);
		PackedPlanCache.FlightClaim firstClaim = cache.beginFlight(fingerprint, context, first);
		PackedPlanCache.FlightClaim secondClaim = cache.beginFlight(fingerprint, context, second);
		ExecutorService executor = Executors.newSingleThreadExecutor();
		try {
			Future<PackedPlanCache.FlightClaim> pendingThird = executor
					.submit(() -> cache.beginFlight(fingerprint, context, third));
			try {
				pendingThird.get(100L, TimeUnit.MILLISECONDS);
			} catch (TimeoutException expectedWhileSaturated) {
				// A bounded coordinator may wait for capacity, but it may never become untracked.
			}
			cache.fail(firstClaim, new IllegalStateException("release saturated test slot"));
			PackedPlanCache.FlightClaim thirdClaim = pendingThird.get(5L, TimeUnit.SECONDS);
			PackedPlanCache.FlightClaim duplicate = cache.beginFlight(fingerprint, context, third);

			assertTrue(thirdClaim.owner());
			assertFalse(duplicate.owner());
			assertSame(thirdClaim.flight(), duplicate.flight());
			cache.fail(thirdClaim, new IllegalStateException("complete saturated test flight"));
		} finally {
			cache.fail(secondClaim, new IllegalStateException("complete second saturated test flight"));
			executor.shutdownNow();
		}
	}

	private static PackedPlanCache.Context context(long dataRevision) {
		return new PackedPlanCache.Context(1L, 2L, 3L, 4L, 5L, 6L, dataRevision);
	}

	private static TupleExpr connectedJoin(String leftObject, String rightObject) {
		SimpleValueFactory values = SimpleValueFactory.getInstance();
		return new Join(
				new StatementPattern(Var.of("subject"), Var.of("leftPredicate", values.createIRI("urn:left")),
						Var.of(leftObject)),
				new StatementPattern(Var.of("subject"), Var.of("rightPredicate", values.createIRI("urn:right")),
						Var.of(rightObject)));
	}
}
